sp_theme.css_variables:
/* ==============================
   THEME TOKENS
   ============================== */

/* LIGHT MODE */
:root {

  /* PRIMARY (Blue system) */
  --color-primary: #4DA3FF;
  --color-primary-dark: #2F7FD6;
  --color-primary-soft: #EAF4FF;

  /* ACCENT (MTG Orange) */
  --color-accent: #FFA348;
  --color-accent-soft: #FFF4E8;

  /* NEUTRALS */
  --color-bg-primary: #FFFFFF;
  --color-bg-secondary: #F6F7F8;
  --color-bg-tertiary: #EDEFF1;

  --color-text-primary: #232323;
  --color-text-secondary: #5B5E62;

  --color-border: #DEDFE0;

  /* BUTTONS */
  --btn-primary-bg: #4DA3FF;
  --btn-primary-hover: #2F7FD6;
  --btn-primary-text: #FFFFFF;

  --btn-secondary-bg: transparent;
  --btn-secondary-border: #4DA3FF;
  --btn-secondary-text: #4DA3FF;

  /* STATES */
  --color-danger: #AB1C1C;
}

/* DARK MODE */
 [data-theme="dark"]{

  --color-primary: #4DA3FF;
  --color-primary-dark: #6BB8FF;
  --color-primary-soft: #1E2A36;

  --color-accent: #FFA348;
  --color-accent-soft: #2F2418;

  --color-bg-primary: #131B22;
  --color-bg-secondary: #1B252D;
  --color-bg-tertiary: #232F38;

  --color-text-primary: #F1F6F1;
  --color-text-secondary: #BDBFC0;

  --color-border: #37383B;

  --btn-primary-bg: #4DA3FF;
  --btn-primary-hover: #6BB8FF;
  --btn-primary-text: #131B22;

  --btn-secondary-bg: transparent;
  --btn-secondary-border: #4DA3FF;
  --btn-secondary-text: #4DA3FF;

  --color-danger: #D99A9A;
}

/* ==============================
   TYPOGRAPHY & SPACING
   ============================== */

:root {
  --fs-xs: 0.75rem;
  --fs-sm: 1rem;
  --fs-md: 1.25rem;
  --fs-lg: 1.5rem;
  --fs-xl: 1.75rem;
  --fs-xxl: 2rem;
  --fs-xxxl: 2.25rem;

  --sp-xs: 0.5rem;
  --sp-sm: 0.75rem;
  --sp-md: 1rem;
  --sp-lg: 1.25rem;
  --sp-xl: 1.5rem;
}

/* ==============================
   GLOBAL
   ============================== */

.mtg-grid {
  display: flex;
  flex-direction: column;
  gap: var(--sp-md);
  color: var(--color-text-primary);
  background: var(--color-bg-primary);
  margin-bottom:var(--sp-xl);
  font-size: var(--fs-lg);
}

/* ==============================
   SEARCH BAR
   ============================== */

.mtg-grid__search {
  display: flex;
  justify-content: center;
  margin-bottom: var(--sp-xl);
}

.mtg-search__form {
  display: flex;
  width: 100%;
  max-width: 50rem;
  gap: var(--sp-sm);
  padding: var(--sp-sm);
  border-radius: 0.75rem;
  /*background: var(--color-bg-secondary);
  border: 1px solid var(--color-border);*/
}

.mtg-search__input {
  flex-grow: 1;
  padding: var(--sp-sm) var(--sp-md);
  border-radius: 0.5rem;
  border: 1px solid var(--color-border);
  background: var(--color-bg-primary);
  color: var(--color-text-primary);
}

.mtg-search__input:focus {
  border-color: var(--color-primary);
  outline: none;
}

.mtg-search__btn {
  padding: var(--sp-sm) var(--sp-md);
  border-radius: 0.5rem;
  font-size: var(--fs-lg);
  cursor: pointer;
}

.mtg-search__btn--primary {
  background: var(--btn-primary-bg);
  color: var(--btn-primary-text);
  border: 1px solid var(--btn-primary-bg);
}

.mtg-search__btn--primary:hover {
  background: var(--btn-primary-hover);
}

.mtg-search__btn--secondary {
  background: var(--btn-secondary-bg);
  border: 1px solid var(--btn-secondary-border);
  color: var(--btn-secondary-text);
}

.mtg-search__btn--secondary:hover {
  background: var(--color-bg-primary);
  color: white;
}

/* ==============================
   GRID & CARD LAYOUT WITH SCALING
   ============================== */

:root {
  --mtg-card-base-width: 22rem; /* default width */
  --mtg-card-scale: 1;          /* 1 = normal size */
  --mtg-card-gap: 1rem;         /* base gap between cards */
  --mtg-card-padding: 0.25rem;  /* base padding inside item */
}

.mtg-grid__container {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(calc(var(--mtg-card-base-width) * var(--mtg-card-scale)), 1fr));
  gap: calc(var(--mtg-card-gap) * var(--mtg-card-scale));
  justify-content: center;
}

.mtg-grid__item {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: calc(var(--mtg-card-padding) * var(--mtg-card-scale));
  box-sizing: border-box;
}

.mtg-card {
  display: flex;
  flex-direction: column;
  align-items: center;
  width: calc(var(--mtg-card-base-width) * var(--mtg-card-scale));
  padding: calc(var(--mtg-card-padding) * var(--mtg-card-scale));
  box-sizing: border-box;
  cursor: pointer;
  transition: transform 0.12s ease, box-shadow 0.12s ease;
  background: transparent;
  border-radius: 8px;
}

.mtg-card:hover {
  transform: scale(1.06);
}

/* CARD BODY */
.mtg-card__body {
  display: inline-block;
  position: relative;
  width: 100%;
  justify-content: center;
  align-items: center;
}

/* CARD IMAGE */
.mtg-card__image {
  display: block;
  width: 100%;
  height: auto;
  object-fit: contain;
  border-radius: 5%;
}

/* FOIL OVERLAY */
.mtg-card__foil {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  z-index: 2;
  border-radius: 5%;
}

/* CARD FOOTER */
.mtg-card__footer {
  width: 100%;
  text-align: center;
  margin-top: calc(0.5rem * var(--mtg-card-scale));
  font-size: var(--fs-sm);
  color: var(--color-text-primary);
}

.mtg-card__meta {
  font-size: var(--fs-lg);
  color: var(--color-text-secondary);
}

/* ==============================
   PAGINATION STYLING
   ============================== */

.mtg-grid__pagination {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 1rem;
  font-size: var(--fs-lg);
  margin: var(--sp-lg) 0 var(--sp-xl 0);
}

.mtg-grid__page-info {
  /*font-size: var(--fs-sm);*/
  color: var(--color-text-primary);
}

input[type=number]::-webkit-outer-spin-button,
input[type=number]::-webkit-inner-spin-button {
    -webkit-appearance: none;
    margin: 0;

}

input[type=number] {
    -moz-appearance: textfield;
    appearance: textfield;
}

/* ==============================
   ADVANCED SEARCH MODAL (RESTORED)
   ============================== */

.mtg-advanced-search {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  z-index: 9999;
  display: flex;
  justify-content: center;
  align-items: center;
  color: var(--color-text-primary);
}

.mtg-advanced-search__overlay {
  position: absolute;
  width: 100%;
  height: 100%;
  background: rgba(0,0,0,0.5);
}

.mtg-advanced-search__content {
  position: relative;
  background: var(--color-bg-primary);
  border-radius: 8px;
  padding: 1.5rem;
  width: 100rem;
  max-width: 90%;
  max-height: 80vh;
  z-index: 10;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.mtg-advanced-search__header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 1rem;
}

.mtg-advanced-search__header h3 {
  color: var(--color-text-primary);
}

.mtg-advanced-search__close {
  background: transparent;
  border: none;
  font-size: var(--fs-xxxl);
  color: var(--color-text-primary);
  cursor: pointer;
}

.mtg-advanced-search__body {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
  overflow-y: auto;
  flex: 1;
  padding-right: 0.5rem;
}

.mtg-advanced-search__body::-webkit-scrollbar {
  width: 8px;
}

.mtg-advanced-search__body::-webkit-scrollbar-thumb {
  background: var(--color-border);
  border-radius: 4px;
}

.mtg-advanced-search__body::-webkit-scrollbar-track {
  background: var(--color-bg-secondary);
}

.mtg-advanced-search__column {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.mtg-advanced-search__column label {
  display: flex;
  flex-direction: column;
  font-size: 1.8rem;
  color: var(--color-text-primary);
  margin-bottom: 0.25rem;
}

.mtg-advanced-search__condition-row {
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: 0.4rem;
  margin-bottom: 0.25rem;
}

.mtg-advanced-search__condition-row select[ng-if] {
  width: 6rem;
  min-width: 3.5rem;
  padding: 0.2rem 0.4rem;
  font-size: 1.6rem;
}

.mtg-advanced-search__condition-row input,
.mtg-advanced-search__condition-row select:not([ng-if]) {
  flex: 1;
  padding: 0.4rem 0.5rem;
  border-radius: 6px;
  border: 1px solid var(--color-border);
  font-size: 1.6rem;
  box-sizing: border-box;
  background: var(--color-bg-primary);
  color: var(--color-text-primary);
}

.mtg-advanced-search__condition-row input:focus,
.mtg-advanced-search__condition-row select:focus {
  border-color: var(--color-primary);
  outline: none;
}

.mtg-advanced-search__condition-row button {
  background: transparent;
  border: none;
  cursor: pointer;
  color: var(--color-danger);
  font-size: 1.5rem;
  flex-shrink: 0;
}

.mtg-query-builder > button {
  margin-top: 0.25rem;
  font-size: 1.5rem;
  padding: 0.25rem 0.5rem;
  border-radius: 6px;
  border: 1px solid var(--color-border);
  background: var(--color-bg-secondary);
  color: var(--color-text-primary);
  cursor: pointer;
}

.mtg-query-builder > button:hover {
  background: var(--color-accent-soft);
}

.mtg-advanced-search__colors {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  margin-top: 0.25rem;
}

.mtg-color-option {
  position: relative;
  display: inline-block;
  width: 2.2rem;
  height: 2.2rem;
  cursor: pointer;
  border-radius: 50%;
  border: 1px solid var(--color-border);
  background: var(--color-bg-secondary);
  transition: all 0.2s ease;
}

.mtg-color-option input {
  position: absolute;
  opacity: 0;
  width: 0;
  height: 0;
}

.mtg-color-option__icon {
  width: 100%;
  height: 100%;
  display: block;
  border-radius: 50%;
  pointer-events: none;
}

.mtg-color-option input:checked + .mtg-color-option__icon {
  border: 2px solid var(--color-primary);
  box-shadow: 0 0 0 3px rgba(77,163,255,0.35);
  background: var(--color-primary-soft);
}

.mtg-color-option:hover::after {
  content: attr(data-label);
  position: absolute;
  bottom: 125%;
  left: 50%;
  transform: translateX(-50%);
  background: var(--color-text-primary);
  color: var(--color-bg-primary);
  font-size: 1.2rem;
  padding: 0.25rem 0.5rem;
  border-radius: 4px;
  white-space: nowrap;
  pointer-events: none;
  opacity: 0.9;
  z-index: 20;
}

.mtg-advanced-search__footer {
  display: flex;
  justify-content: center;
  margin-top: 0.75rem;
}

.mtg-advanced-search__submit {
  padding: 0.5rem 1.25rem;
  border-radius: 6px;
  background: var(--btn-primary-bg);
  color: var(--btn-primary-text);
  border: none;
  cursor: pointer;
  font-weight: 600;
}

.mtg-advanced-search__submit:hover {
  background: var(--btn-primary-hover);
}

/* ==============================
   DEBUG PANEL
   ============================== */

.mtg-debug__pre {
  max-height: 25rem;
  font-size: var(--fs-sm);
  overflow: auto;
  background: black;
  color: #0f0;
  padding: var(--sp-sm);
}
